// AVONET morphology + ecology for a species by its IOC common name.
// Returns null when the species isn't in AVONET (drives the '-' UI state).
export function avonetFor(name: string): AvonetRecord | null {
  return AVONET[name] ?? null;
}

export default AVONET;
